using System.Net;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// Fix 1: Changed Singleton → Scoped. A singleton factory that resolves the
// scoped IUserService violates scope validation, which .NET 9 now enforces
// at startup in the Development environment (ValidateScopes is on by default).
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
// Fix 2: Use ConfigurePrimaryHttpMessageHandler with SocketsHttpHandler.
// .NET 9 changed the default primary handler from HttpClientHandler to
// SocketsHttpHandler; the old cast would throw InvalidCastException.
// Fix 3: Allowlist non-sensitive headers for Trace-level logging.
// .NET 9 redacts ALL header values by default; only sensitive headers are
// kept redacted here so the rest remain visible for debugging.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() =>
        new SocketsHttpHandler { UseCookies = false })
    .RedactLoggedHeaders(header =>
        header == "Authorization" || header == "Cookie" || header == "Set-Cookie");
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // Fix 4: .NET 9 silently ignores X-Forwarded-* headers from proxies not
    // in KnownProxies / KnownNetworks. Add your reverse-proxy address(es).
    options.KnownProxies.Add(IPAddress.Parse("TODO: proxy IP"));
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

